class CM:
    def __enter__(self):
        print("enter")
        return self
    def __exit__(self, *exc):
        print("exit")
        return False

try:
    with CM():
        print("body")
        raise ValueError("boom")
    print("after")
except ValueError as e:
    print(type(e).__name__)

from contextlib import contextmanager

@contextmanager
def cm():
    print("setup")
    yield 42
    print("teardown")

try:
    with cm() as v:
        raise ValueError("boom")
except ValueError as e:
    print(type(e).__name__)
